css:
.loader {
  display: inline-block;
  width: 50px;
  height: 50px;
  border-radius: 12px;
  background: linear-gradient(135deg, #6366f1, #8b5cf6);
  animation: cube 1.2s ease-in-out infinite;
  box-shadow: 0 18px 32px rgba(99, 102, 241, 0.22);
}
@keyframes cube {
  0%, 100% { transform: rotate(0deg) scale(0.9); border-radius: 16px; }
  50% { transform: rotate(180deg) scale(1.08); border-radius: 50%; }
}
